const body = $json.body ?? $json;

const requestId =
  body.request_id ||
  body.engine_payload?.request_id ||
  body.chat_request?.request_id ||
  crypto.randomUUID();

const chatMessage =
  body.message ||
  body.chat_request?.message ||
  body.prompt ||
  body.idea ||
  body.description ||
  body.input_brief?.description ||
  '';

const inferredTitle =
  body.project_name ||
  body.engine_payload?.project_name ||
  body.chat_request?.project_name ||
  (chatMessage ? chatMessage.slice(0, 80) : 'Innexia AI Strategy Engine Opportunity');

const incomingMeta = body.meta || {};
const incomingOrg = body.organization || body.engine_payload?.organization || {};
const incomingExecution = body.execution_options || body.engine_payload?.execution_options || {};
const incomingBrief = body.input_brief || body.engine_payload?.input_brief || {};

return [{
  json: {
    request_id: requestId,
    project_name: inferredTitle,
    analysis_type: body.analysis_type || body.engine_payload?.analysis_type || 'new_business',
    language: body.language || body.engine_payload?.language || 'es',
    organization: {
      name: incomingOrg.name || 'Innexia',
      industry: incomingOrg.industry || 'tecnologia y salud',
      country: incomingOrg.country || 'Panama'
    },
    input_brief: {
      title: incomingBrief.title || inferredTitle,
      description: incomingBrief.description || chatMessage,
      objective: incomingBrief.objective || body.objective || 'Evaluar viabilidad y diseñar estrategia de lanzamiento',
      problem_statement: incomingBrief.problem_statement || chatMessage || 'Analizar una nueva oportunidad de negocio o iniciativa estratégica',
      constraints: incomingBrief.constraints || body.constraints || []
    },
    context_sources: body.context_sources || body.engine_payload?.context_sources || { use_tavily: true, use_internal_context: false },
    execution_options: {
      run_modules: incomingExecution.run_modules || ['market_intelligence','bmc','strategy','roadmap','finance','risks','verdict','activities'],
      generate_kanban: incomingExecution.generate_kanban ?? true,
      generate_gantt: incomingExecution.generate_gantt ?? true,
      persist_outputs: incomingExecution.persist_outputs ?? true,
      strict_json: incomingExecution.strict_json ?? true
    },
    chat_context: body.chat_context || {
      session_id: body.session_id || body.chat_request?.session_id || null,
      user_id: body.user_id || body.chat_request?.user_id || null,
      conversation_summary: body.conversation_summary || null,
      original_message: chatMessage,
      intent: body.intent || null,
      analysis_scope: body.analysis_scope || null
    },
    meta: {
      workflow_version: 'v5.3-enterprise',
      source: incomingMeta.source || body.source || 'chat_gateway',
      created_at: incomingMeta.created_at || new Date().toISOString(),
      session_id: incomingMeta.session_id || body.session_id || null,
      user_id: incomingMeta.user_id || body.user_id || null
    }
  }
}];

const root = $('Normalize Input').first().json;
const supervisor = $('Run Supervisor').first().json;
const market_analysis = $('Run Market Intelligence').first().json;
return [{json:{...root, supervisor, market_analysis}}];

function safeNodeJson(nodeName) {
  try {
    const node = $(nodeName).first();
    return node?.json ?? null;
  } catch (error) {
    return null;
  }
}

const normalizedInput = safeNodeJson('Normalize Input') || {};
const supervisor = safeNodeJson('Run Supervisor') || {};
const market = safeNodeJson('Run Market Intelligence') || {};
const bmc = safeNodeJson('Run BMC') || {};
const strategy = safeNodeJson('Run Strategy') || {};
const finance = safeNodeJson('Run Finance') || {};
const risks = safeNodeJson('Run Risks') || {};
const roadmap = safeNodeJson('Run Roadmap') || {};

const payload = {
  request_id: normalizedInput.request_id || null,
  project_name: normalizedInput.project_name || null,
  language: normalizedInput.language || 'es',
  input: normalizedInput,
  supervisor,
  market_analysis: market?.market_analysis || market || {},
  bmc: bmc?.bmc || bmc || {},
  strategy: strategy?.strategy || strategy || {},
  finance: finance?.finance || finance || {},
  risks: risks?.risks || risks || [],
  roadmap: roadmap?.roadmap || roadmap || {},
  meta: {
    assembled_at: new Date().toISOString(),
    available_modules: {
      supervisor: !!supervisor,
      market: !!market,
      bmc: !!bmc,
      strategy: !!strategy,
      finance: !!finance,
      risks: !!risks,
      roadmap: !!roadmap
    }
  }
};

return [{ json: payload }];

const pre = $('Assemble Pre-Verdict Payload').first().json;
const verdict = $('Run Verdict').first().json;
return [{json:{...pre, verdict}}];

function safeNodeJson(nodeName) {
  try {
    const node = $(nodeName).first();
    return node?.json ?? null;
  } catch (error) {
    return null;
  }
}

const normalizedInput = safeNodeJson('Normalize Input') || {};
const supervisor = safeNodeJson('Run Supervisor') || {};
const market = safeNodeJson('Run Market Intelligence') || {};
const bmc = safeNodeJson('Run BMC') || {};
const strategy = safeNodeJson('Run Strategy') || {};
const finance = safeNodeJson('Run Finance') || {};
const risks = safeNodeJson('Run Risks') || {};
const roadmap = safeNodeJson('Run Roadmap') || {};
const verdict = safeNodeJson('Run Verdict') || {};
const activities = safeNodeJson('Run Activities') || {};

const payload = {
  request_id: normalizedInput.request_id || null,
  project_name: normalizedInput.project_name || null,
  language: normalizedInput.language || 'es',
  input: normalizedInput,
  supervisor,
  market_analysis: market?.market_analysis || market || {},
  bmc: bmc?.bmc || bmc || {},
  strategy: strategy?.strategy || strategy || {},
  finance: finance?.finance || finance || {},
  risks: risks?.risks || risks || [],
  roadmap: roadmap?.roadmap || roadmap || {},
  verdict: verdict?.verdict || verdict || {},
  activities: activities?.activities || activities || [],
  meta: {
    assembled_at: new Date().toISOString(),
    available_modules: {
      supervisor: !!supervisor,
      market: !!market,
      bmc: !!bmc,
      strategy: !!strategy,
      finance: !!finance,
      risks: !!risks,
      roadmap: !!roadmap,
      verdict: !!verdict,
      activities: !!activities
    }
  }
};

return [{ json: payload }];

function safeNodeJson(nodeName) {
  try {
    const node = $(nodeName).first();
    return node?.json ?? null;
  } catch (error) {
    return null;
  }
}

const normalized = safeNodeJson('Normalize Input') || {};
const fullPayload = safeNodeJson('Assemble Full Payload') || {};
const consolidated = safeNodeJson('Run Consolidator') || {};
const kanbanRaw = safeNodeJson('Run Kanban Generator') || {};
const ganttRaw = safeNodeJson('Run Gantt Generator') || {};

const kanban =
  kanbanRaw?.kanban ||
  kanbanRaw?.board ||
  kanbanRaw?.items ||
  kanbanRaw ||
  [];

const gantt =
  ganttRaw?.gantt ||
  ganttRaw?.timeline ||
  ganttRaw?.tasks ||
  ganttRaw ||
  [];

const summary =
  consolidated?.summary ||
  consolidated?.result?.summary ||
  {};

const verdict =
  consolidated?.verdict ||
  fullPayload?.verdict ||
  consolidated?.result?.verdict ||
  {};

const scores =
  consolidated?.scores ||
  consolidated?.result?.scores ||
  {};

const finalResult = {
  request_id: normalized.request_id || consolidated?.request_id || null,
  project_name: consolidated?.project_name || normalized.project_name || null,
  status: consolidated?.status || 'completed',
  summary,
  scores,
  verdict,
  market_analysis:
    consolidated?.market_analysis ||
    fullPayload?.market_analysis ||
    consolidated?.result?.market_analysis ||
    {},
  business_model_canvas:
    consolidated?.bmc ||
    fullPayload?.bmc ||
    consolidated?.result?.bmc ||
    consolidated?.result?.business_model_canvas ||
    {},
  strategy:
    consolidated?.strategy ||
    fullPayload?.strategy ||
    consolidated?.result?.strategy ||
    {},
  financials:
    consolidated?.finance ||
    fullPayload?.finance ||
    consolidated?.result?.finance ||
    consolidated?.result?.financials ||
    {},
  risks:
    consolidated?.risks ||
    fullPayload?.risks ||
    consolidated?.result?.risks ||
    [],
  roadmap:
    consolidated?.roadmap ||
    fullPayload?.roadmap ||
    consolidated?.result?.roadmap ||
    {},
  activities:
    consolidated?.activities ||
    fullPayload?.activities ||
    consolidated?.result?.activities ||
    [],
  kanban,
  gantt,
  raw_consolidated: consolidated
};

return [{
  json: {
    success: true,
    request_id: finalResult.request_id,
    project_name: finalResult.project_name,
    status: finalResult.status,
    result: finalResult,
    metrics: {
      workflow_version: normalized?.meta?.workflow_version || 'v5.3-enterprise-core-v2.3',
      generated_at: new Date().toISOString()
    },
    error: null
  }
}];
